use live
go

SELECT *
	--PART_ID
	--, MAX(EFFECTIVE_DATE) AS EFF_DATE
	--, MAX(ISNULL(DISCONTINUE_DATE, GETDATE() + 1)) AS DISC_DATE
	--, DEFAULT_UNIT_PRICE
FROM CUST_PRICE_EFFECT 
WHERE ISNULL(DISCONTINUE_DATE, GETDATE() + 1) > GETDATE()
	AND EFFECTIVE_DATE <= GETDATE()
order BY PART_ID
	, EFFECTIVE_DATE

SELECT customer_id, PART_ID, count(*)
FROM CUST_PRICE_EFFECT 
WHERE ISNULL(DISCONTINUE_DATE, GETDATE() + 1) > GETDATE()
	AND EFFECTIVE_DATE <= GETDATE()
group by customer_id, PART_ID
having count(*) > 1

