select * from CUST_PRICE_EFFECT where (effective_date < '1/1/2016' and DISCONTINUE_DATE is null) or DISCONTINUE_DATE < '1/1/2018'

select * from CUST_PRICE_EFFECT where (effective_date is null and DISCONTINUE_DATE is null) order by create_date

select * from CUST_PRICE_EFFECT where DISCONTINUE_DATE is null order by create_date
select * from CUST_PRICE_EFFECT where EFFECTIVE_DATE is null AND DISCONTINUE_DATE >= GETDATE() order by create_date

select customer_id
, part_id
, p.PLANNER_USER_ID
, cpe.create_date
, cpe.EFFECTIVE_DATE
, cpe.DISCONTINUE_DATE
from CUST_PRICE_EFFECT cpe
inner join part p
on p.id = cpe.part_id
where DISCONTINUE_DATE is null 
and year(effective_date) = '2016'  
AND P.PLANNER_USER_ID = 'FIN'
order by create_date

/*
UPDATE CUST_PRICE_EFFECT 
SET DISCONTINUE_DATE = '12/31/2017'
WHERE EFFECTIVE_DATE IS NULL
	AND DISCONTINUE_DATE IS NULL
	AND CREATE_DATE < '1/1/2017'
--18648 ROWS

UPDATE CUST_PRICE_EFFECT 
SET DISCONTINUE_DATE = '12/31/2017'
FROM CUST_PRICE_EFFECT CPE
INNER JOIN PART P
ON CPE.PART_ID = P.ID
WHERE YEAR(CPE.EFFECTIVE_DATE) = '2016'
	AND CPE.DISCONTINUE_DATE IS NULL
	AND P.PLANNER_USER_ID = 'FIN'
--420 ROWS

UPDATE CUST_PRICE_EFFECT 
SET DISCONTINUE_DATE = DATEADD(YEAR, 1, EFFECTIVE_DATE)
FROM CUST_PRICE_EFFECT CPE
INNER JOIN PART P
ON CPE.PART_ID = P.ID
WHERE YEAR(CPE.EFFECTIVE_DATE) = '2017'
	AND CPE.DISCONTINUE_DATE IS NULL
	AND P.PLANNER_USER_ID = 'FIN'
--140 ROWS


*/